template <class T, unsigned int granularity, unsigned int fusion_degree, unsigned int compute_iterations, bool TemperateUnroll>
void benchmark_func(T seed, T *g_data, long total_elements, long stride, long big_stride) {
    #pragma omp parallel
    {
        long num_threads = omp_get_num_threads();
        long thread_id = omp_get_thread_num();

        long block_size = (total_elements + num_threads - 1) / num_threads;
        long start_idx = thread_id * block_size;
        if (start_idx >= total_elements) return;
        long end_idx = start_idx + block_size;
        if (end_idx > total_elements) end_idx = total_elements;

        T tmps[granularity];

        for(long idx = start_idx; idx < end_idx; idx += stride) {
            for(int k=0; k<fusion_degree; k++){
                for(int j=0; j<granularity; j++){
                    long access_idx = idx + j*stride + k*big_stride;
                    if (access_idx < total_elements)
                        tmps[j] = g_data[access_idx];
                    else
                        tmps[j] = conv_int<T>(0);

                    int unroll_factor = TemperateUnroll ? 4 : 128;
                    (void)unroll_factor; // Avoid unused warning
                    for(int i=0; i<compute_iterations; i++){
                        tmps[j] = mad(tmps[j], tmps[j], seed);
                    }
                }

                T sum = conv_int<T>(0);
                for(int j=0; j<granularity; j+=2) {
                    if (j+1 < granularity)
                        sum = mad(tmps[j], tmps[j+1], sum);
                    else
                        sum = mad(tmps[j], conv_int<T>(0), sum);
                }

                if( equal(sum, conv_int<T>(-1)) ) {
                    long write_idx = idx + k*big_stride;
                    if (write_idx < total_elements)
                        g_data[write_idx] = sum;
                }
            }
        }
    }
}

double get_time() {
    return omp_get_wtime();
}

void runbench_warmup(double *cd, long size){
    const long reduced_grid_size = size/(ELEMENTS_PER_THREAD)/128;
    const int BLOCK_SIZE = 256;
    const int TOTAL_REDUCED_BLOCKS = reduced_grid_size/BLOCK_SIZE;
    if (TOTAL_REDUCED_BLOCKS <= 0) return;

    long total_elements = TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;
    if (total_elements > size) total_elements = size;

    benchmark_func< short, ELEMENTS_PER_THREAD, FUSION_DEGREE, 0, true >((short)1, (short*)cd, total_elements, BLOCK_SIZE, TOTAL_REDUCED_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD);
}

