    const int TOTAL_BLOCKS = compute_grid_size/BLOCK_SIZE;
    if (TOTAL_BLOCKS <= 0) return;

    const long long computations = (ELEMENTS_PER_THREAD*(long long)compute_grid_size+(2*ELEMENTS_PER_THREAD*compute_iterations)*(long long)compute_grid_size)*FUSION_DEGREE;
    const long long memoryoperations = size;

    long total_elements = TOTAL_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;
    if (total_elements > size) total_elements = size;
    long stride = BLOCK_SIZE;
    long big_stride = TOTAL_BLOCKS * BLOCK_SIZE * ELEMENTS_PER_THREAD;

    double start_time, end_time;
    float kernel_time_mad_sp, kernel_time_mad_dp, kernel_time_mad_hp, kernel_time_mad_int;

